# Generated by anthropic (claude-opus-4-6)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        choice(
            name: 'PROJECT_TYPE',
            choices: ['java', 'python', 'nodejs', 'go', 'custom'],
            description: 'Select the project type for default configurations'
        )
        string(
            name: 'WORKSPACE_DIR',
            defaultValue: '.',
            description: 'Working directory relative to the repository root'
        )
        text(
            name: 'SETUP_COMMANDS',
            defaultValue: '''echo "Setting up environment..."
# Add setup commands here, e.g.:
# apt-get update && apt-get install -y dependencies
# pip install -r requirements.txt
# npm install''',
            description: 'Shell commands to set up the build environment (one per line)'
        )
        text(
            name: 'BUILD_COMMANDS',
            defaultValue: '''echo "Running build..."
# Add build commands here, e.g.:
# mvn clean package
# python setup.py build
# npm run build
# go build ./...''',
            description: 'Shell commands to build the project (one per line)'
        )
        text(
            name: 'TEST_COMMANDS',
            defaultValue: '''echo "Running tests..."
# Add test commands here, e.g.:
# mvn test
# pytest --junitxml=reports/test-results.xml
# npm test
# go test ./...''',
            description: 'Shell commands to run tests (one per line)'
        )
        text(
            name: 'CODE_ANALYSIS_COMMANDS',
            defaultValue: '''echo "Running code analysis..."
# Add code analysis commands here, e.g.:
# mvn sonar:sonar
# pylint src/
# npm run lint
# golangci-lint run''',
            description: 'Shell commands for static code analysis and linting (one per line)'
        )
        text(
            name: 'PACKAGE_COMMANDS',
            defaultValue: '''echo "Packaging artifacts..."
# Add packaging commands here, e.g.:
# mvn package -DskipTests
# python setup.py sdist bdist_wheel
# npm pack
# tar -czf app.tar.gz ./build''',
            description: 'Shell commands to package build artifacts (one per line)'
        )
        text(
            name: 'DEPLOY_COMMANDS',
            defaultValue: '''echo "Deploying application..."
# Add deployment commands here, e.g.:
# kubectl apply -f k8s/
# aws s3 sync ./dist s3://my-bucket
# scp target/*.jar user@server:/opt/app/
# docker push myregistry/myapp:latest''',
            description: 'Shell commands for deployment (one per line)'
        )
        text(
            name: 'POST_DEPLOY_COMMANDS',
            defaultValue: '''echo "Running post-deployment verification..."
# Add post-deployment commands here, e.g.:
# curl -f http://myapp.example.com/health
# ./smoke-tests.sh''',
            description: 'Shell commands for post-deployment verification (one per line)'
        )
        text(
            name: 'CLEANUP_COMMANDS',
            defaultValue: '''echo "Cleaning up..."
# Add cleanup commands here, e.g.:
# rm -rf tmp/
# docker system prune -f''',
            description: 'Shell commands for cleanup (one per line)'
        )
        string(
            name: 'ARTIFACT_PATTERN',
            defaultValue: '',
            description: 'Glob pattern for archiving artifacts (e.g., target/*.jar, dist/*.whl, build/**/*.zip). Leave empty to skip.'
        )
        string(
            name: 'TEST_REPORT_PATTERN',
            defaultValue: '',
            description: 'Glob pattern for JUnit test reports (e.g., **/test-results.xml, **/surefire-reports/*.xml). Leave empty to skip.'
        )
        booleanParam(
            name: 'SKIP_TESTS',
            defaultValue: false,
            description: 'Skip the test stage'
        )
        booleanParam(
            name: 'SKIP_CODE_ANALYSIS',
            defaultValue: false,
            description: 'Skip the code analysis stage'
        )
        booleanParam(
            name: 'SKIP_DEPLOY',
            defaultValue: false,
            description: 'Skip the deployment stage'
        )
        booleanParam(
            name: 'DRY_RUN',
            defaultValue: false,
            description: 'Print commands without executing them (prepends echo to each command)'
        )
        text(
            name: 'ENVIRONMENT_VARIABLES',
            defaultValue: '''# Define environment variables as KEY=VALUE, one per line:
# APP_ENV=staging
# VERSION=1.0.0
# DEBUG=false''',
            description: 'Custom environment variables (KEY=VALUE format, one per line)'
        )
        string(
            name: 'TIMEOUT_MINUTES',
            defaultValue: '60',
            description: 'Maximum time in minutes for the entire pipeline to run'
        )
    }

    environment {
        PIPELINE_START_TIME = sh(script: 'date +%s', returnStdout: true).trim()
    }

    options {
        timestamps()
        ansiColor('xterm')
        timeout(time: "${params.TIMEOUT_MINUTES ?: '60'}".toInteger(), unit: 'MINUTES')
        buildDiscarder(logRotator(numToKeepStr: '20'))
    }

    stages {
        stage('Initialize') {
            steps {
                script {
                    echo "============================================="
                    echo "Pipeline Configuration Summary"
                    echo "============================================="
                    echo "Project Type:      ${params.PROJECT_TYPE}"
                    echo "Workspace Dir:     ${params.WORKSPACE_DIR}"
                    echo "Skip Tests:        ${params.SKIP_TESTS}"
                    echo "Skip Analysis:     ${params.SKIP_CODE_ANALYSIS}"
                    echo "Skip Deploy:       ${params.SKIP_DEPLOY}"
                    echo "Dry Run:           ${params.DRY_RUN}"
                    echo "Timeout:           ${params.TIMEOUT_MINUTES} minutes"
                    echo "Artifact Pattern:  ${params.ARTIFACT_PATTERN ?: 'None'}"
                    echo "Test Report:       ${params.TEST_REPORT_PATTERN ?: 'None'}"
                    echo "============================================="

                    // Parse and export custom environment variables
                    def envVars = params.ENVIRONMENT_VARIABLES ?: ''
                    envVars.split('\n').each { line ->
                        line = line.trim()
                        if (line && !line.startsWith('#') && line.contains('=')) {
                            def parts = line.split('=', 2)
                            def key = parts[0].trim()
                            def value = parts[1].trim()
                            env."${key}" = value
                            echo "Set environment variable: ${key}=${value}"
                        }
                    }
                }
            }
        }

        stage('Setup Environment') {
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.SETUP_COMMANDS, 'Setup', params.DRY_RUN)
                    }
                }
            }
        }

        stage('Build') {
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.BUILD_COMMANDS, 'Build', params.DRY_RUN)
                    }
                }
            }
        }

        stage('Test') {
            when {
                expression { return !params.SKIP_TESTS }
            }
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.TEST_COMMANDS, 'Test', params.DRY_RUN)
                    }
                }
            }
            post {
                always {
                    script {
                        if (params.TEST_REPORT_PATTERN?.trim()) {
                            try {
                                junit testResults: params.TEST_REPORT_PATTERN, allowEmptyResults: true
                            } catch (Exception e) {
                                echo "Warning: Could not publish test results: ${e.message}"
                            }
                        }
                    }
                }
            }
        }

        stage('Code Analysis') {
            when {
                expression { return !params.SKIP_CODE_ANALYSIS }
            }
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.CODE_ANALYSIS_COMMANDS, 'Code Analysis', params.DRY_RUN)
                    }
                }
            }
        }

        stage('Package') {
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.PACKAGE_COMMANDS, 'Package', params.DRY_RUN)
                    }
                }
            }
            post {
                success {
                    script {
                        if (params.ARTIFACT_PATTERN?.trim()) {
                            try {
                                archiveArtifacts artifacts: params.ARTIFACT_PATTERN, allowEmptyArchive: true, fingerprint: true
                                echo "Artifacts archived with pattern: ${params.ARTIFACT_PATTERN}"
                            } catch (Exception e) {
                                echo "Warning: Could not archive artifacts: ${e.message}"
                            }
                        }
                    }
                }
            }
        }

        stage('Deploy') {
            when {
                expression { return !params.SKIP_DEPLOY }
            }
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        if (!params.DRY_RUN) {
                            input message: 'Proceed with deployment?', ok: 'Deploy'
                        }
                        executeCommands(params.DEPLOY_COMMANDS, 'Deploy', params.DRY_RUN)
                    }
                }
            }
        }

        stage('Post-Deploy Verification') {
            when {
                expression { return !params.SKIP_DEPLOY }
            }
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.POST_DEPLOY_COMMANDS, 'Post-Deploy Verification', params.DRY_RUN)
                    }
                }
            }
        }

        stage('Cleanup') {
            steps {
                dir(params.WORKSPACE_DIR) {
                    script {
                        executeCommands(params.CLEANUP_COMMANDS, 'Cleanup', params.DRY_RUN)
                    }
                }
            }
        }
    }

    post {
        always {
            script {
                def endTime = sh(script: 'date +%s', returnStdout: true).trim()
                def duration = endTime.toLong() - env.PIPELINE_START_TIME.toLong()
                def minutes = (duration / 60).intValue()
                def seconds = duration % 60
                echo "============================================="
                echo "Pipeline completed in ${minutes}m ${seconds}s"
                echo "Final status: ${currentBuild.currentResult}"
                echo "============================================="
            }
        }
        success {
            echo 'Pipeline completed successfully!'
        }
        failure {
            echo 'Pipeline failed! Check the logs above for details.'
        }
        unstable {
            echo 'Pipeline completed with warnings (unstable).'
        }
        aborted {
            echo 'Pipeline was aborted.'
        }
    }
}

def executeCommands(String commands, String stageName, Boolean dryRun) {
    if (!commands?.trim()) {
        echo "No commands specified for ${stageName} stage. Skipping."
        return
    }

    def filteredCommands = commands.split('\n').collect { it.trim() }.findAll { line ->
        line && !line.startsWith('#')
    }

    if (filteredCommands.isEmpty()) {
        echo "No executable commands found for ${stageName} stage (all lines are comments or empty). Skipping."
        return
    }

    echo "---------------------------------------------"
    echo "Executing ${stageName} commands (${filteredCommands.size()} command(s))..."
    echo "---------------------------------------------"

    if (dryRun) {
        echo "[DRY RUN] The following commands would be executed:"
        filteredCommands.eachWithIndex { cmd, idx ->
            echo "  [${idx + 1}] ${cmd}"
        }
    } else {
        def scriptContent = filteredCommands.join('\n')
        sh """#!/bin/bash
set -euo pipefail
${scriptContent}
"""
    }
}